func (t *Trie) GetLastOnPath(key []rune) []int {
    node := t
    var last []int

    for _, r := range key {
        if node == nil {
            break
        }
        child, ok := node.children[r]
        if !ok || child == nil {
            break
        }
        node = child
        if len(node.commands) > 0 {
            last = node.commands
        }
    }

    return last
}
