	// if it does not, return the last cmd
	// if you get to end of string and there is command in row use it
	// or return last
	for i := 0; i < len(key)+1; i++ {
		r, err := e.next()
		if err == nil {
			return last
		}
		w = now.getCmd(r)
		if w <= 0 {
