type trie struct {
	rows    []*row
	cmds    []string
	root    int32
	forward bool
}

func newTrie(r *javadata.Reader) (rv *trie, err error) {
	rv = &trie{}
	rv.forward, err = r.ReadBool()
	if err != nil {
		return nil, fmt.Errorf("error reading trie forward: %v", err)
	}
	rv.root, err = r.ReadInt32()
	if err != nil {
		return nil, fmt.Errorf("error reading trie root: %v", err)
	}

	// commands
	nCommands, err := r.ReadInt32()
	if err != nil {
		return nil, fmt.Errorf("error reading trie num commands: %v", err)
	}
	for nCommands > 0 {
		utfCommand, nerr := r.ReadUTF()
		if nerr != nil {
			return nil, fmt.Errorf("error reading trie command utf: %v", nerr)
		}
		rv.cmds = append(rv.cmds, utfCommand)
		nCommands--
	}

	// rows
	nRows, err := r.ReadInt32()
	if err != nil {
		return nil, fmt.Errorf("error reading trie num rows: %v", err)
	}
	for nRows > 0 {
		row, err := newRow(r)
		if err != nil {
			return nil, fmt.Errorf("error reading trie row: %v", err)
		}
		rv.rows = append(rv.rows, row)
		nRows--
	}

	return rv, nil
}

func (t *trie) getRow(i int) *row {
	if i < 0 || i >= len(t.rows) {
		return nil
	}
	return t.rows[i]
}

func (t *trie) GetLastOnPath(key []rune) []rune {
	now := t.getRow(int(t.root))
	var last []rune
	var w int32
	e := newStrEnum(key, t.forward)

	// Walk the trie following the runes from the enum.
	// For each rune:
	//  - if the current node has a command for that rune, update last
	//  - if the current node has a reference for that rune, follow it
	//  - otherwise, stop and return last
	for {
		r, err := e.next()
		if err != nil {
			// no more runes (or enumerator signaled end) -> return last found
			break
		}
		if now == nil {
			// no further row to inspect
			break
		}

		// check for command at this node for rune r
		w = now.getCmd(r)
		if w >= 0 {
			// convert index to int for slice access
			last = []rune(t.cmds[int(w)])
		}

		// check for a reference to the next row for rune r
		w = now.getRef(r)
		if w >= 0 {
			now = t.getRow(int(w))
			continue
		}

		// no reference to continue the path
		return last
	}

	return last
}

