		}
		cell, err := newCell(r)
		if err != nil {
			return nil, fmt.Errorf("error reading cell: %v", err)
		}

		rv.cells[c] = cell
		nCells--
	}
	return rv, nil
}

func (r *row) getCmd(way rune) int32 {
	c := r.at(way)
	if c != nil {
		return c.cmd
	}
	return -1
}

